SELECT plan_name 
FROM forest_management_plans
WHERE strftime('%Y', 'now') BETWEEN strftime('%Y', start_date) AND strftime('%Y', end_date);

SELECT plan_name, start_date, end_date
FROM forest_management_plans
ORDER BY start_date ASC;

SELECT completion_percentage
FROM plan_progress
WHERE status = 'Active';

SELECT plan_name, status
FROM forest_management_plans
ORDER BY status;

SELECT class_name, description
FROM landscape_classes
ORDER BY class_name ASC;
